final class KeychainManager {
    static let shared = KeychainManager()

    func save(_ value: String, for key: String) {
        let data = Data(value.utf8)
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
        let attributes: [String: Any] = query.merging([
            kSecValueData as String: data
        ]) { _, new in new }
        SecItemAdd(attributes as CFDictionary, nil)
    }

    func read(_ key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)
        guard status == errSecSuccess,
              let data = item as? Data,
              let value = String(data: data, encoding: .utf8) else { return nil }
        return value
    }
}

final class SecureAPIClient {
    static let shared = SecureAPIClient()
    private let decoder: JSONDecoder
    private let encoder: JSONEncoder

    init() {
        decoder = JSONDecoder()
        encoder = JSONEncoder()
        decoder.dateDecodingStrategy = .iso8601
        encoder.dateEncodingStrategy = .iso8601
    }

    func send<T: Decodable, U: Encodable>(
        path: String,
        method: String,
        body: U? = nil,
        token: String,
        environment: APIEnvironment
    ) async throws -> T {
        guard let url = URL(string: path, relativeTo: environment.baseURL) else {
            throw AppError.invalidURL
        }

        var request = URLRequest(url: url)
        request.httpMethod = method
        request.timeoutInterval = 15
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        request.setValue(signature(for: body), forHTTPHeaderField: "X-Signature")
        request.setValue(ISO8601DateFormatter().string(from: Date()), forHTTPHeaderField: "X-Timestamp")

        if let body {
            request.httpBody = try encoder.encode(body)
        }

        let (data, response) = try await URLSession.shared.data(for: request)

        guard let httpResponse = response as? HTTPURLResponse else {
            throw AppError.network("Invalid response.")
        }

        switch httpResponse.statusCode {
        case 200...299:
            do {
                return try decoder.decode(T.self, from: data)
            } catch {
                throw AppError.decoding
            }
        case 401:
            throw AppError.unauthorized
        default:
            if let errorResponse = try? decoder.decode(APIErrorResponse.self, from: data) {
                throw AppError.server(errorResponse.message)
            }
            throw AppError.server("Request failed with status \(httpResponse.statusCode).")
        }
    }

    func send<T: Decodable>(
        path: String,
        method: String,
        token: String,
        environment: APIEnvironment
    ) async throws -> T {
        try await send(path: path, method: method, body: Optional<String>.none, token: token, environment: environment)
    }

    private func signature<U: Encodable>(for body: U?) -> String {
        let secret = KeychainManager.shared.read("api_secret") ?? "demo_secret"
        let payload: Data
        if let body, let encoded = try? encoder.encode(body) {
            payload = encoded
        } else {
            payload = Data()
        }
        let key = SymmetricKey(data: Data(secret.utf8))
        let mac = HMAC<SHA256>.authenticationCode(for: payload, using: key)
        return Data(mac).map { String(format: "%02hhx", $0) }.joined()
    }
}

@MainActor
final class MarketDataStream: ObservableObject {
    @Published var quotes: [String: Quote] = [:]

    private var timer: AnyCancellable?
    private let symbols = ["AAPL", "TSLA", "MSFT", "NVDA", "AMZN", "META"]

    func start() {
        guard timer == nil else { return }
        timer = Timer.publish(every: 1.2, on: .main, in: .common)
            .autoconnect()
            .sink { [weak self] _ in
                self?.updateQuotes()
            }
        updateQuotes()
    }

    func stop() {
        timer?.cancel()
        timer = nil
    }

    private func updateQuotes() {
        for symbol in symbols {
            let previous = quotes[symbol]?.price ?? seedPrice(for: symbol)
            let delta = Double.random(in: -2.2...2.2)
            let price = max(1, previous + delta)
            let change = price - seedPrice(for: symbol)
            let base = seedPrice(for: symbol)
            let quote = Quote(
                symbol: symbol,
                price: price,
                change: change,
                changePercent: (change / base) * 100,
                bid: price - 0.03,
                ask: price + 0.03,
                volume: Int.random(in: 50_000...5_000_000),
                timestamp: Date()
            )
            quotes[symbol] = quote
        }
    }

    private func seedPrice(for symbol: String) -> Double {
        switch symbol {
        case "AAPL": return 189.20
        case "TSLA": return 171.35
        case "MSFT": return 421.10
        case "NVDA": return 911.50
        case "AMZN": return 182.80
        case "META": return 504.00
        default: return 100
        }
    }
}

@MainActor
final class TradingViewModel: ObservableObject {
    @Published var portfolio: Portfolio = .empty
    @Published var orders: [TradeOrder] = []
    @Published var selectedSymbol: String = "AAPL"
    @Published var tradeSide: TradeSide = .buy
    @Published var orderType: OrderType = .market
    @Published var quantityText: String = "10"
    @Published var limitPriceText: String = ""
    @Published var isSubmitting: Bool = false
    @Published var isLoadingPortfolio: Bool = false
    @Published var errorMessage: String?
    @Published var successMessage: String?

    let marketData = MarketDataStream()
    private var cancellables = Set<AnyCancellable>()
    private let client = SecureAPIClient.shared
    private let appState: AppState

    init(appState: AppState) {
        self.appState = appState
        bindMarketData()
        marketData.start()
        seedDemoData()
    }

    private func bindMarketData() {
        marketData.$quotes
            .receive(on: DispatchQueue.main)
            .sink { [weak self] quotes in
                guard let self else { return }
                self.portfolio.positions = self.portfolio.positions.map { position in
                    var updated = position
                    if let quote = quotes[position.symbol] {
                        updated.currentPrice = quote.price
                    }
                    return updated
                }
                self.recalculatePortfolio()
            }
            .store(in: &cancellables)
    }

    func loadPortfolio() async {
        isLoadingPortfolio = true
        defer { isLoadingPortfolio = false }
        recalculatePortfolio()
    }

    func placeOrder() async {
        successMessage = nil
        errorMessage = nil

        guard let quantity = Double(quantityText), quantity > 0 else {
            errorMessage = AppError.invalidInput("Enter a valid quantity.").localizedDescription
            return
        }

        var limitPrice: Double?
        if orderType == .limit {
            guard let price = Double(limitPriceText), price > 0 else {
                errorMessage = AppError.invalidInput("Enter a valid limit price.").localizedDescription
                return
            }
            limitPrice = price
        }

        isSubmitting = true
        defer { isSubmitting = false }

        let request = TradeRequest(
            symbol: selectedSymbol,
            side: tradeSide,
            orderType: orderType,
            quantity: quantity,
            limitPrice: limitPrice
        )

        do {
            _ = try? await Task.sleep(nanoseconds: 600_000_000)

            let executionPrice = executionPrice(for: request)
            try validateOrder(request, executionPrice: executionPrice)
            let order = simulateOrderExecution(request: request, executionPrice: executionPrice)
            orders.insert(order, at: 0)
            apply(order: order)
            successMessage = "\(order.side.rawValue) order filled: \(order.quantity.clean) \(order.symbol) @ \(executionPrice.currency)"
        } catch {
            errorMessage = error.localizedDescription
        }
    }

    private func validateOrder(_ request: TradeRequest, executionPrice: Double) throws {
        let grossAmount = request.quantity * executionPrice

        switch request.side {
        case .buy:
            if grossAmount > portfolio.buyingPower {
                throw AppError.invalidInput("Insufficient buying power.")
            }
        case .sell:
            let existingQuantity = portfolio.positions.first(where: { $0.symbol == request.symbol })?.quantity ?? 0
            if request.quantity > existingQuantity {
                throw AppError.invalidInput("Insufficient shares to sell.")
            }
        }
    }

    private func simulateOrderExecution(request: TradeRequest, executionPrice: Double) -> TradeOrder {
        TradeOrder(
            id: UUID().uuidString,
            symbol: request.symbol,
            side: request.side,
            orderType: request.orderType,
            quantity: request.quantity,
            limitPrice: request.limitPrice,
            status: .filled,
            filledQuantity: request.quantity,
            averageFillPrice: executionPrice,
            createdAt: Date()
        )
    }

    private func executionPrice(for request: TradeRequest) -> Double {
        let quote = marketData.quotes[request.symbol]
        switch request.orderType {
        case .market:
            return request.side == .buy ? (quote?.ask ?? 100) : (quote?.bid ?? 100)
        case .limit:
            return request.limitPrice ?? quote?.price ?? 100
        }
    }

    private func apply(order: TradeOrder) {
        guard let fillPrice = order.averageFillPrice else { return }

        switch order.side {
        case .buy:
            let cost = order.quantity * fillPrice
            portfolio.cashBalance -= cost
            if let index = portfolio.positions.firstIndex(where: { $0.symbol == order.symbol }) {
                var existing = portfolio.positions[index]
                let totalShares = existing.quantity + order.quantity
                let totalCost = (existing.averageCost * existing.quantity) + cost
                existing.quantity = totalShares
                existing.averageCost = totalCost / totalShares
                existing.currentPrice = fillPrice
                portfolio.positions[index] = existing
            } else {
                portfolio.positions.append(Position(symbol: order.symbol, quantity: order.quantity, averageCost: fillPrice, currentPrice: fillPrice))
            }
        case .sell:
            let proceeds = order.quantity * fillPrice
            portfolio.cashBalance += proceeds
            if let index = portfolio.positions.firstIndex(where: { $0.symbol == order.symbol }) {
                var existing = portfolio.positions[index]
                existing.quantity -= order.quantity
                existing.currentPrice = fillPrice
                if existing.quantity <= 0.0001 {
                    portfolio.positions.remove(at: index)
                } else {
                    portfolio.positions[index] = existing
                }
            }
        }

        recalculatePortfolio()
    }

    private func recalculatePortfolio() {
        let positionsValue = portfolio.positions.reduce(0) { $0 + $1.marketValue }
        portfolio.equity = portfolio.cashBalance + positionsValue
        portfolio.buyingPower = portfolio.cashBalance * 2
        portfolio.dayPnL = portfolio.positions.reduce(0) { $0 + $1.unrealizedPnL }
    }

    private func seedDemoData() {
        portfolio = Portfolio(
            cashBalance: 75_000,
            buyingPower: 150_000,
            equity: 100_000,
            dayPnL: 0,
            positions: [
                Position(symbol: "AAPL", quantity: 120, averageCost: 182.10, currentPrice: 189.20),
                Position(symbol: "MSFT", quantity: 40, averageCost: 406.15, currentPrice: 421.10),
                Position(symbol: "NVDA", quantity: 15, averageCost: 874.00, currentPrice: 911.50)
            ]
        )
        recalculatePortfolio()
    }
}

